import{c as a,Q as t,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"How do I approve a release stage?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/approve-release-stage.md","filePath":"guide/recipes/admin/approve-release-stage.md","lastUpdated":1778912818000}'),s={name:"guide/recipes/admin/approve-release-stage.md"};function i(l,e,n,p,d,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-approve-a-release-stage" tabindex="-1">How do I approve a release stage? <a class="header-anchor" href="#how-do-i-approve-a-release-stage" aria-label="Permalink to &quot;How do I approve a release stage?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>A designated <strong>SPOC</strong> for at least one of the stage&#39;s instances, or <strong>Platform Admin</strong>.</p></div><p>Stages can be gated by approval — they pause at <code>awaiting_approval</code> until a SPOC signs off. The Console shows you only the <strong>Approve</strong> button for stages where you are eligible.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Releases</strong> and click the release.</li><li>The pipeline visualisation shows each stage. Stages awaiting approval have a <strong>blue border</strong> and an <strong>Approve</strong> button on each environment box.</li><li>Review the change — click the environment box to see the diff between current and target.</li><li>Click <strong>Approve</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The stage moves out of <code>awaiting_approval</code>. What happens next depends on your release configuration:</p><ul><li>If the next gate is <strong>auto-trigger</strong>, the stage starts deploying immediately.</li><li>If it&#39;s <strong>manual trigger</strong>, the stage moves to <code>awaiting_trigger</code> and waits for someone to <a href="./trigger-release-stage">trigger it</a>.</li></ul><p>Your approval is recorded in the release timeline with your operator ID and timestamp.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./trigger-release-stage">How do I trigger a paused release stage?</a></li><li><a href="./create-release">How do I create a release?</a></li></ul>',11)])])}const u=a(s,[["render",i]]);export{c as __pageData,u as default};
